GUIAnim = class("GUIAnim")

local subAnimMap = {
    ["scale"] = GUISubAnimScale,
    ["alpha"] = GUISubAnimAlpha,
    ["move"] = GUISubAnimMove,
}

function GUIAnim:ctor(window, config, callBack)
    --LogUtil.log("GUIAnim:ctor " .. inspect.inspect(config))

    self.window = window
    self.config = config
    self.callBack = callBack
    self.sync = true
    self.isEnd = false
    self.subAnims = {}

    if not self.config.sync or self.config.sync == "false" then
        self.sync = false
    end

    self:parseGUISubAnim()

    --LogUtil.log("GUIAnim:ctor self.sync " .. tostring(self.sync))
end

function GUIAnim:parseGUISubAnim()
    for i = 1, #self.config.childs do
        local child = self.config.childs[i]
        local class = subAnimMap[child.animType]
        if class then
            local subAnim = class.new(self.window, child)
            subAnim:play()
            table.insert(self.subAnims, subAnim)
        end
    end
end

function GUIAnim:update(time)
    if self.isEnd then
        return
    end

    if self.sync then
        self.isEnd = true
        for _, subAnim in pairs(self.subAnims) do
            subAnim:update()
            if not subAnim.isEnd then
                self.isEnd = false
            end
        end
    else
        if #self.subAnims == 0 then
            self.isEnd = true
        else
            self.subAnims[1]:update()

            if self.subAnims[1].isEnd then
                table.remove(self.subAnims, 1)
            end
        end
    end

    if self.isEnd and self.callBack then
        (self.callBack)()
    end
end

return GUIAnim